from dataclasses import dataclass, field
from typing import Literal
from enum import IntEnum

class Reversibility(IntEnum):
    HIGH   = 1   # two-way door
    MEDIUM = 2   # partially reversible
    LOW    = 3   # one-way door

@dataclass
class ReversibilityScore:
    data_artifact:   Reversibility
    integration:     Reversibility
    rollback_cost:   Reversibility
    eval_reference:  Reversibility
    regulatory:      Reversibility

    @property
    def total(self) -> int:
        return sum([
            self.data_artifact, self.integration,
            self.rollback_cost, self.eval_reference, self.regulatory,
        ])

    @property
    def routing(self) -> Literal["fast-track", "spike+ADR", "full-review"]:
        if self.total <= 5:
            return "fast-track"
        elif self.total <= 10:
            return "spike+ADR"
        else:
            return "full-review"

    def report(self) -> str:
        return (
            f"Total: {self.total}/15  →  {self.routing}\n"
            f"  Data artifact impact : {self.data_artifact.name}\n"
            f"  Integration surface  : {self.integration.name}\n"
            f"  Rollback cost        : {self.rollback_cost.name}\n"
            f"  Eval reference change: {self.eval_reference.name}\n"
            f"  Regulatory lock-in   : {self.regulatory.name}"
        )

# Example: switching embedding model
score = ReversibilityScore(
    data_artifact  = Reversibility.LOW,     # must rebuild entire index
    integration    = Reversibility.MEDIUM,  # RAG service boundary
    rollback_cost  = Reversibility.LOW,     # index rebuild = 2+ weeks
    eval_reference = Reversibility.MEDIUM,  # benchmark needs partial relabel
    regulatory     = Reversibility.HIGH,    # no new regulatory scope
)
print(score.report())
# Total: 10/15  →  spike+ADR

import hashlib, json
from pathlib import Path
from dataclasses import dataclass

@dataclass
class IndexManifest:
    embedding_model: str          # e.g. "text-embedding-3-large"
    embedding_dim: int
    chunk_size: int
    chunk_overlap: int
    doc_count: int
    index_version: str            # content hash of this manifest

    @classmethod
    def from_config(cls, cfg: dict, doc_count: int) -> "IndexManifest":
        payload = {k: v for k, v in cfg.items()}
        payload["doc_count"] = doc_count
        version = hashlib.sha256(
            json.dumps(payload, sort_keys=True).encode()
        ).hexdigest()[:12]
        return cls(**cfg, doc_count=doc_count, index_version=version)

    def save(self, index_dir: Path) -> None:
        manifest_path = index_dir / "manifest.json"
        manifest_path.write_text(json.dumps(self.__dict__, indent=2))

    @classmethod
    def load(cls, index_dir: Path) -> "IndexManifest":
        data = json.loads((index_dir / "manifest.json").read_text())
        return cls(**data)

def assert_index_compatible(index_dir: Path, live_config: dict) -> None:
    manifest = IndexManifest.load(index_dir)
    if manifest.embedding_model != live_config["embedding_model"]:
        raise RuntimeError(
            f"Index built with {manifest.embedding_model!r} but "
            f"config specifies {live_config['embedding_model']!r}. "
            "Rebuild the index before deploying."
        )
    if manifest.chunk_size != live_config["chunk_size"]:
        raise RuntimeError(
            f"Chunk size mismatch: index={manifest.chunk_size}, "
            f"config={live_config['chunk_size']}. Rebuild required."
        )
